import React from "react";
import "../styles/Welcome.css";
import { useNavigate } from "react-router-dom";
import avatar from "../assets/robot-avatar.png";

function Welcome() {
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();

    // ✅ After anime login go DIRECTLY to Dashboard
    navigate("/dashboard");
  };

  return (
    <div className="welcome-container">
      <div className="welcome-wrapper">

        {/* LEFT SIDE – ANIME LOGIN */}
        <div className="text-section">
          <div className="login-card">
            <h2>Welcome to MindCare AI</h2>
            <p>Your safe, supportive AI therapist</p>

            <form onSubmit={handleLogin}>
              <input type="text" placeholder="Username" required />
              <input type="password" placeholder="Password" required />
              <button type="submit">Login</button>
            </form>

            <p className="signup-text">
              Don’t have an account?{" "}
              <span onClick={() => navigate("/signup")}>
                Sign up
              </span>
            </p>
          </div>
        </div>

        {/* RIGHT SIDE – IMAGE */}
        <div className="image-section">
          <img src={avatar} alt="AI Therapist Illustration" />
        </div>

      </div>
    </div>
  );
}

export default Welcome;
